import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/link/src/link.component.js';
const tagName = 'made-link';
Component.define('made-link');
/**
 * @summary A link allow users to navigate to a different location. They can be presented in-line inside a paragraph or as standalone text.
 * @documentation '../../components/link/stories/link.mdx'
 *
 * @slot - The link's label.
 * @slot start - Used to place an content before the link's label. Typically used for icons.
 * @slot end - Used to place content after the link's label. Typically used for icons.
 *
 * @csspart base - The component's base wrapper.
 * @csspart end - The container that wraps the end slot.
 * @csspart label - The link's label.
 * @csspart start - The container that wraps the start slot.
 *
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {},
    displayName: 'MadeLink'
});
export default reactWrapper;
